    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Dynamic Balance - 2w 3x/wk',
    'balance',
    3,
    60,
    ARRAY['Improve overall fitness', 'Build strength and endurance']::text[],
    '[]'::jsonb
